import{_ as t,I as c,o as n,c as l,a9 as a,b as i,w as e,a as r,J as o,aa as d}from"./chunks/framework.CyWQssWv.js";const T=JSON.parse('{"title":"引言：为什么需要 sockops？","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"引言：为什么需要 sockops？ | Blog"}]]},"headers":[],"relativePath":"ebpf/sockops/introduction.md","filePath":"ebpf/sockops/introduction.md","lastUpdated":1782414869000}'),b={name:"ebpf/sockops/introduction.md"};function h(_,s,u,k,g,m){const p=c("Mermaid");return n(),l("div",null,[s[1]||(s[1]=a(`<h1 id="引言-为什么需要-sockops" tabindex="-1">引言：为什么需要 sockops？ <a class="header-anchor" href="#引言-为什么需要-sockops" aria-label="Permalink to “引言：为什么需要 sockops？”">​</a></h1><blockquote><p><strong>💡 本章你将理解：</strong></p><ul><li>在 sockops 诞生前，内核 TCP 参数调优面临什么致命缺陷？</li><li>为什么说 sockops 是&quot;TCP 状态机上的可编程传感器与操纵杆&quot;？</li><li>阅读本分册需要哪些前提知识？</li></ul></blockquote><hr><h2 id="一、历史背景-tcp-调优的三次范式跃迁" tabindex="-1">一、历史背景：TCP 调优的三次范式跃迁 <a class="header-anchor" href="#一、历史背景-tcp-调优的三次范式跃迁" aria-label="Permalink to “一、历史背景：TCP 调优的三次范式跃迁”">​</a></h2><h3 id="_1-1-蛮荒时代-全局-sysctl" tabindex="-1">1.1 蛮荒时代：全局 sysctl <a class="header-anchor" href="#_1-1-蛮荒时代-全局-sysctl" aria-label="Permalink to “1.1 蛮荒时代：全局 sysctl”">​</a></h3><p>Linux 内核的第一个 TCP 实现（1990 年代初期）将 TCP 参数——RTO 最小值、拥塞窗口初始值、读写缓冲区大小——硬编码为编译时常量或全局 <code>sysctl</code> 变量。</p><p><strong>致命缺陷：</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>                    ┌──────────────┐</span></span>
<span class="line"><span>                    │  sysctl 全局 │</span></span>
<span class="line"><span>                    │  net.ipv4.   │</span></span>
<span class="line"><span>                    │  tcp_rto_min │</span></span>
<span class="line"><span>                    └──────┬───────┘</span></span>
<span class="line"><span>                           │ 一个值对所有 socket 生效</span></span>
<span class="line"><span>              ┌────────────┼────────────┐</span></span>
<span class="line"><span>              ▼            ▼            ▼</span></span>
<span class="line"><span>         ┌─────────┐ ┌─────────┐ ┌─────────┐</span></span>
<span class="line"><span>         │ 同机房   │ │ 跨大洲   │ │ 移动网络 │</span></span>
<span class="line"><span>         │ RTT=1ms  │ │RTT=200ms│ │ RTT=50ms │</span></span>
<span class="line"><span>         └─────────┘ └─────────┘ └─────────┘</span></span>
<span class="line"><span>              全部使用同一个 RTO 最小值</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>同机房连接只需要 10ms 级的 RTO，但为了兼容跨洲连接，管理员只能将 <code>tcp_rto_min</code> 设为一个&quot;折中值&quot;（源码中为 <code>TCP_RTO_MIN = 200ms</code>，定义于 <code>include/net/tcp.h</code>）。结果是：同机房连接因不必要的长时间等待重传而浪费延迟，跨洲连接又可能因 RTO 过小而过度重传。</p><p>更根本的问题在于：<strong>sysctl 是&quot;空间无关&quot;的</strong>——它无法根据每条连接的实际情况（源/目的 IP、端口、cgroup 归属）做出差异化决策。</p><h3 id="_1-2-用户态代理时代-bpf-cgroup-inet-4-6" tabindex="-1">1.2 用户态代理时代：BPF_CGROUP_INET{4,6}_* <a class="header-anchor" href="#_1-2-用户态代理时代-bpf-cgroup-inet-4-6" aria-label="Permalink to “1.2 用户态代理时代：BPF_CGROUP_INET{4,6}_*”">​</a></h3><p>Linux 4.x 引入了 cgroup BPF 程序类型 <code>BPF_PROG_TYPE_CGROUP_SOCK</code> 和 <code>BPF_CGROUP_INET4_CONNECT</code> 等挂载点（定义于 <code>include/uapi/linux/bpf.h</code>），允许在 <code>connect()</code> / <code>bind()</code> / <code>sendmsg()</code> / <code>recvmsg()</code> 系统调用时触发 BPF 程序执行。</p><p>这解决了&quot;空间感知&quot;问题——BPF 程序可以读取源/目的 IP 和端口，按需决策。但它引出了<strong>新的致命缺陷</strong>：</p><p><strong>缺陷一：建连时间点的信息匮乏</strong></p><div class="language-c line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// CGROUP_SOCK 程序在 connect() 时能看到什么？</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bpf_sock </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sk </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ctx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sk;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // socket 基本信息</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ⚠️ 缺失：TCP 状态机信息（当前在哪个状态？）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ⚠️ 缺失：RTT 测量值（还没有数据包，自然没有 RTT）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ⚠️ 缺失：拥塞窗口、重传统计等运行态参数</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ⚠️ 缺失：TCP 头部选项读写能力</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>建连时刻能获取的信息仅限于 socket 层的通用字段（家族、协议、IP/端口），TCP 层的关键运行参数（RTT、拥塞窗口、状态机位置）完全不可见。</p><p><strong>缺陷二：建连后无法介入</strong></p><p>更致命的是：一旦 <code>connect()</code> 调用返回，cgroup sock 程序就无法再对该连接施加影响了。当 RTO 超时实际触发时、当连接状态在 <code>TIME_WAIT</code> 和 <code>CLOSE_WAIT</code> 之间迁移时、当每个 RTT 被测量时——这些 TCP 栈内部事件对 BPF 程序来说是<strong>盲点</strong>。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>connect() 时刻:       [BPF 程序可介入]</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>       v</span></span>
<span class="line"><span>    建连后的 TCP 生命周期:</span></span>
<span class="line"><span>       ├── RTO 超时触发          [BPF 盲点]</span></span>
<span class="line"><span>       ├── 重传发生              [BPF 盲点]</span></span>
<span class="line"><span>       ├── ESTABLISHED→FIN_WAIT1 [BPF 盲点]</span></span>
<span class="line"><span>       ├── RTT 更新              [BPF 盲点]</span></span>
<span class="line"><span>       └── 收到 TCP 自定义选项    [BPF 盲点]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="_1-3-sockops-时代-tcp-协议栈内置钩子-linux-4-13" tabindex="-1">1.3 sockops 时代：TCP 协议栈内置钩子（Linux 4.13+） <a class="header-anchor" href="#_1-3-sockops-时代-tcp-协议栈内置钩子-linux-4-13" aria-label="Permalink to “1.3 sockops 时代：TCP 协议栈内置钩子（Linux 4.13+）”">​</a></h3><p>2017 年，Linux 4.13 引入了 <code>BPF_PROG_TYPE_SOCK_OPS</code>（源码定义于 <code>include/uapi/linux/bpf.h:1074</code>），彻底改变了上述局面。</p><p><strong>核心突破：将 BPF 程序直接嵌入 TCP 协议栈内部。</strong></p>`,22)),(n(),i(d,null,{default:e(()=>[o(p,{id:"mermaid-77",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%22TCP%20%E5%8D%8F%E8%AE%AE%E6%A0%88%22%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20A%5Btcp_connect%5D%20--%3E%20B%5BSYN%20%E5%8F%91%E9%80%81%5D%0A%20%20%20%20%20%20%20%20C%5Btcp_finish_connect%5D%20--%3E%20D%5BESTABLISHED%5D%0A%20%20%20%20%20%20%20%20E%5Btcp_set_state%5D%20--%3E%20F%5B%E7%8A%B6%E6%80%81%E8%BF%81%E7%A7%BB%5D%0A%20%20%20%20%20%20%20%20G%5Btcp_retransmit_timer%5D%20--%3E%20H%5BRTO%20%E8%B6%85%E6%97%B6%5D%0A%20%20%20%20%20%20%20%20I%5Btcp_rcv_established%5D%20--%3E%20J%5B%E6%94%B6%E5%8C%85%E5%A4%84%E7%90%86%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22sockops%20%E9%92%A9%E5%AD%90%22%0A%20%20%20%20%20%20%20%20B%20-.-%3E%7CTCP_CONNECT_CB%7C%20P%5BBPF%20%E7%A8%8B%E5%BA%8F%5D%0A%20%20%20%20%20%20%20%20D%20-.-%3E%7CACTIVE_ESTABLISHED_CB%7C%20P%0A%20%20%20%20%20%20%20%20F%20-.-%3E%7CSTATE_CB%7C%20P%0A%20%20%20%20%20%20%20%20H%20-.-%3E%7CRTO_CB%7C%20P%0A%20%20%20%20%20%20%20%20J%20-.-%3E%7CPARSE_HDR_OPT_CB%7C%20P%0A%20%20%20%20end%0A%0A%20%20%20%20P%20--%3E%7Cbpf_setsockopt%7C%20K%5B%E4%BF%AE%E6%94%B9%20TCP%20%E5%8F%82%E6%95%B0%5D%0A%20%20%20%20P%20--%3E%7Cbpf_sock_ops_cb_flags_set%7C%20L%5B%E5%90%AF%E7%94%A8%E5%90%8E%E7%BB%AD%E5%9B%9E%E8%B0%83%5D%0A%20%20%20%20P%20--%3E%7Cbpf_sock_map_update%7C%20M%5B%E6%8F%92%E5%85%A5%20sockmap%5D%0A"})]),fallback:e(()=>[...s[0]||(s[0]=[r(" Loading... ",-1)])]),_:1})),s[2]||(s[2]=a(`<p>sockops 将钩子植入 TCP 协议栈的动作本身（tcp_connect、tcp_finish_connect、tcp_set_state）而非系统调用入口。这意味着 BPF 程序能够：</p><ol><li><strong>在 TCP 栈的&quot;决策瞬间&quot;介入</strong>：<code>TCP_CONNECT_CB</code> 在 SYN 即将发出前触发，此时可以修改拥塞窗口初始值；<code>ACTIVE_ESTABLISHED_CB</code> 在三次握手完成后立即触发，此时可以修改缓冲区大小或启用后续通知回调</li><li><strong>访问 TCP 层运行时数据</strong>：<code>srtt_us</code>（平滑 RTT）、<code>snd_cwnd</code>（拥塞窗口）、<code>packets_out</code>（在途报文数）等字段在 BPF 上下文中直接可读</li><li><strong>订阅后续事件流</strong>：通过 <code>bpf_sock_ops_cb_flags_set()</code> 设置回调标志位，可以在 RTO 超时、状态迁移、每次 RTT 测量时收到异步通知</li><li><strong>按 cgroup 维度管理</strong>：sockops 附加到 cgroup 上，继承 cgroup 的层级管理能力——父 cgroup 的程序自动影响所有子 cgroup 的 TCP 连接</li></ol><hr><h2 id="二、sockops-解决的核心矛盾" tabindex="-1">二、sockops 解决的核心矛盾 <a class="header-anchor" href="#二、sockops-解决的核心矛盾" aria-label="Permalink to “二、sockops 解决的核心矛盾”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                     核心矛盾                                  │</span></span>
<span class="line"><span>│                                                              │</span></span>
<span class="line"><span>│   TCP 连接需要按“连接属性”做差异化调优                          │</span></span>
<span class="line"><span>│           ↕                                                   │</span></span>
<span class="line"><span>│   但调优所需的决策信息在 TCP 栈内部，不在用户态可见             │</span></span>
<span class="line"><span>│           ↕                                                   │</span></span>
<span class="line"><span>│   解决方案：将调优逻辑下沉到 TCP 栈内部执行                      │</span></span>
<span class="line"><span>│           ↕                                                   │</span></span>
<span class="line"><span>│   ===&gt; sockops：运行在 TCP 栈内的可编程策略引擎                 │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="_2-1-具体解决的四大痛点" tabindex="-1">2.1 具体解决的四大痛点 <a class="header-anchor" href="#_2-1-具体解决的四大痛点" aria-label="Permalink to “2.1 具体解决的四大痛点”">​</a></h3><table tabindex="0"><thead><tr><th>痛点</th><th>sockops 之前的方案</th><th>sockops 方案</th></tr></thead><tbody><tr><td><strong>差异化 TCP 参数</strong></td><td>sysctl 全局 — 一根筋</td><td>每连接可在建连时通过 <code>bpf_setsockopt</code> 设置；同步操作码（<code>TIMEOUT_INIT</code> 等）直接返回参数值</td></tr><tr><td><strong>建连后持续介入</strong></td><td>不可能 — connect() 之后就是盲区</td><td>通知回调机制：订阅 <code>RTO_CB</code> / <code>STATE_CB</code> / <code>RTT_CB</code> 持续获取事件</td></tr><tr><td><strong>自定义 TCP 选项</strong></td><td>需修改内核源码</td><td><code>HDR_OPT_LEN_CB</code> + <code>WRITE_HDR_OPT_CB</code> + <code>PARSE_HDR_OPT_CB</code> 三件套</td></tr><tr><td><strong>连接级负载均衡</strong></td><td>需第三方代理（如 IPVS）做连接分发</td><td>建连时将 socket 自动插入 sockmap，配合 sk_skb 程序实现内核态四层代理</td></tr></tbody></table><hr><h2 id="三、前置知识指引" tabindex="-1">三、前置知识指引 <a class="header-anchor" href="#三、前置知识指引" aria-label="Permalink to “三、前置知识指引”">​</a></h2><p>阅读本分册前，你应当在以下领域具备基础知识。若对某个概念不熟，建议先补阅读对应的内核文档。</p><h3 id="_3-1-bpf-最小知识集合" tabindex="-1">3.1 BPF 最小知识集合 <a class="header-anchor" href="#_3-1-bpf-最小知识集合" aria-label="Permalink to “3.1 BPF 最小知识集合”">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>你需要理解到什么程度</th><th>补充阅读</th></tr></thead><tbody><tr><td>BPF 程序类型 (<code>bpf_prog_type</code>)</td><td>不同程序类型决定了可访问的上下文和辅助函数；sockops 是其中一种，附着于 cgroup</td><td><code>Documentation/bpf/libbpf/</code></td></tr><tr><td>BPF map</td><td>KV 存储，用于 BPF 程序间共享数据、跨事件传递状态；sockops 常用 sockmap/sockhash 存储 socket 引用</td><td><code>Documentation/bpf/maps.rst</code></td></tr><tr><td>BPF 辅助函数</td><td>程序可调用的内核函数白名单；sockops 能调用 <code>bpf_setsockopt</code>、<code>bpf_sock_ops_cb_flags_set</code> 等</td><td><code>include/uapi/linux/bpf.h</code> 辅助函数 ID 枚举</td></tr><tr><td>BPF 验证器</td><td>加载时静态检查：禁止越界访问、循环、不可达指令；理解&quot;验证器友好&quot;的编程范式</td><td><code>Documentation/bpf/verifier.rst</code></td></tr><tr><td><code>libbpf</code> 加载模型</td><td><code>SEC()</code> 宏标记程序节、<code>bpf_object__open</code> → <code>bpf_object__load</code> → <code>bpf_program__attach</code> 三步曲</td><td><code>tools/lib/bpf/README.rst</code></td></tr></tbody></table><h3 id="_3-2-tcp-最小知识集合" tabindex="-1">3.2 TCP 最小知识集合 <a class="header-anchor" href="#_3-2-tcp-最小知识集合" aria-label="Permalink to “3.2 TCP 最小知识集合”">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>你需要理解到什么程度</th><th>关键源码</th></tr></thead><tbody><tr><td>TCP 状态机</td><td>CLOSED → LISTEN → SYN_RECV → ESTABLISHED → FIN_WAIT → CLOSED 的完整生命周期</td><td><code>include/net/tcp_states.h</code></td></tr><tr><td>三次握手</td><td>SYN → SYN+ACK → ACK 的时序和 socket 状态迁移（主动/被动打开的区别）</td><td><code>net/ipv4/tcp_input.c:tcp_rcv_state_process()</code></td></tr><tr><td>RTO (Retransmission Timeout)</td><td>TCP 重传超时机制：RTO 定时器、指数退避、tcp_retransmit_timer 处理函数</td><td><code>net/ipv4/tcp_timer.c</code></td></tr><tr><td>拥塞窗口与慢启动</td><td><code>snd_cwnd</code> 的增减逻辑、ssthresh 阈值、拥塞控制算法可插拔机制</td><td><code>net/ipv4/tcp_cong.c</code></td></tr><tr><td>TCP 头部选项格式</td><td>Kind(1B) + Length(1B) + Value 的 TLV 编码格式、选项空间限制（40 字节最大选项区）</td><td>RFC 9293 第 3.2 节</td></tr></tbody></table><p>⚠️ <strong>易错点</strong>：如果你对 TCP 状态机不熟悉，务必先阅读 <code>include/net/tcp_states.h</code> 中的状态枚举和 <code>net/ipv4/tcp.c:tcp_set_state()</code> 的状态迁移逻辑。sockops 的 <code>STATE_CB</code> 回调、<code>TIMEOUT_INIT</code> 操作、建连回调都精确绑定在特定状态上——不理解状态机将导致无法预期程序何时被触发。</p><h3 id="_3-3-cgroup-v2-最小知识集合" tabindex="-1">3.3 cgroup v2 最小知识集合 <a class="header-anchor" href="#_3-3-cgroup-v2-最小知识集合" aria-label="Permalink to “3.3 cgroup v2 最小知识集合”">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>你需要理解到什么程度</th></tr></thead><tbody><tr><td>cgroup 层级结构</td><td>子 cgroup 继承父 cgroup 的资源限制和 BPF 程序；sockops 在 cgroup 层级上生效</td></tr><tr><td>cgroup BPF 挂载</td><td><code>bpftool cgroup attach</code> 命令；程序附着于 cgroup 目录，影响该 cgroup 内所有进程创建的 socket</td></tr><tr><td>cgroup socket 归属判定</td><td>socket 创建时继承进程的当前 cgroup；sockops 通过 <code>BPF_CGROUP_RUN_PROG_SOCK_OPS</code> 宏查找 socket 所属 cgroup</td></tr></tbody></table><hr><h2 id="四、sockops-在内核中的定位" tabindex="-1">四、sockops 在内核中的定位 <a class="header-anchor" href="#四、sockops-在内核中的定位" aria-label="Permalink to “四、sockops 在内核中的定位”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户态</span></span>
<span class="line"><span>  │  open() / write()  等系统调用</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>────────────────────── 系统调用层 ──────────────────────</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>VFS / Socket 层 (net/socket.c)</span></span>
<span class="line"><span>  │  socket-&gt;ops-&gt;connect() / sendmsg() 等</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>TCP 协议层 (net/ipv4/tcp.c, tcp_input.c, tcp_output.c, tcp_timer.c)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  sockops 钩子就是插在这一层的：</span></span>
<span class="line"><span>  │  · tcp_connect() → BPF_SOCK_OPS_TCP_CONNECT_CB</span></span>
<span class="line"><span>  │  · tcp_finish_connect() → BPF_SOCK_OPS_ACTIVE_ESTABLISHED_CB</span></span>
<span class="line"><span>  │  · tcp_set_state() → BPF_SOCK_OPS_STATE_CB</span></span>
<span class="line"><span>  │  · tcp_retransmit_timer() → BPF_SOCK_OPS_RTO_CB</span></span>
<span class="line"><span>  │  · tcp_rcv_established() → bpf_skops_parse_hdr()</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├──→ tcp_call_bpf() [include/net/tcp.h:2905]</span></span>
<span class="line"><span>  ├──→ BPF_CGROUP_RUN_PROG_SOCK_OPS() [include/linux/bpf-cgroup.h:344]</span></span>
<span class="line"><span>  ├──→ __cgroup_bpf_run_filter_sock_ops() [kernel/bpf/cgroup.c:1721]</span></span>
<span class="line"><span>  └──→ BPF 程序执行 ◄── 你的 sockops 程序</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  BPF 辅助函数（在 sockops 上下文中可用）：</span></span>
<span class="line"><span>  │  · bpf_setsockopt() [net/core/filter.c:5863]</span></span>
<span class="line"><span>  │  · bpf_getsockopt() [net/core/filter.c:5957]</span></span>
<span class="line"><span>  │  · bpf_sock_ops_cb_flags_set() [net/core/filter.c:5999]</span></span>
<span class="line"><span>  │  · bpf_sock_map_update() → 关联 sockmap</span></span>
<span class="line"><span>  │  · bpf_load_hdr_opt() / bpf_store_hdr_opt() → 自定义头部选项</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>IP 层 → 链路层 → 硬件</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br></div></div><p>sockops 不拦截也不修改网络数据包本身（那是 <code>BPF_PROG_TYPE_SOCKET_FILTER</code> 或 XDP 的工作）。它修改的是 <strong>TCP 连接的运行时参数</strong>：拥塞窗口、RTO 值、缓冲区大小、回调订阅。</p><hr><h2 id="五、本书阅读约定" tabindex="-1">五、本书阅读约定 <a class="header-anchor" href="#五、本书阅读约定" aria-label="Permalink to “五、本书阅读约定”">​</a></h2><p>全书使用以下标注规范：</p><table tabindex="0"><thead><tr><th>标注标记</th><th>含义</th></tr></thead><tbody><tr><td><code>函数名 @ 文件路径:行号</code></td><td>内核源码函数的精确位置标注</td></tr><tr><td>⚠️ <strong>易错点</strong></td><td>容易误解或踩坑的设计细节</td></tr><tr><td>💡 <strong>设计动机</strong></td><td>解释为什么内核选择当前的实现方式</td></tr><tr><td>🔒 <strong>并发安全警示</strong></td><td>涉及锁、RCU、引用计数的安全语义</td></tr></tbody></table><hr><blockquote><p><strong>📝 一句话回顾：</strong> sockops 是嵌在 TCP 协议栈事件驱动点上的 BPF 钩子，不是包过滤器，而是连接级的&quot;智能传感器与参数控制器&quot;，它通过 cgroup 施加策略，在三次握手、状态迁移、重传超时等关键决策瞬间让策略生效。</p></blockquote><p>接下来请阅读 <a href="./design-and-data"><code>design-and-data.md</code></a>，深入解剖 sockops 的核心数据结构与设计哲学。</p>`,28))])}const C=t(b,[["render",h]]);export{T as __pageData,C as default};
